import java.util.*;

public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-directory>");
            System.exit(1);
        }

        String sourceDir = args[0];
        try {
            processDirectory(new File(sourceDir));
            System.out.println("Transformation completed successfully");
        } catch (Exception e) {
            System.err.println("Error during transformation: " + e.getMessage());
            e.printStackTrace();
        }
    }

    private static void processDirectory(File dir) throws IOException {
        if (!dir.exists()) {
            throw new IOException("Directory does not exist: " + dir.getAbsolutePath());
        }

        File[] files = dir.listFiles((d, name) -> name.endsWith(".java"));
        if (files != null) {
            for (File file : files) {
                processFile(file);
            }
        }

        File[] subdirs = dir.listFiles(File::isDirectory);
        if (subdirs != null) {
            for (File subdir : subdirs) {
                processDirectory(subdir);
            }
        }
    }

    private static void processFile(File file) throws IOException {
        try {
            String content = new String(Files.readAllBytes(file.toPath()));
            CompilationUnit cu = StaticJavaParser.parse(content);

            // Apply the transformation
            Liquibase480TransformationVisitor visitor = new Liquibase480TransformationVisitor();
            cu.accept(visitor, null);

            // Write back the modified content
            try (PrintWriter out = new PrintWriter(file)) {
                out.println(cu.toString());
            }
        } catch (Exception e) {
            // Skip files that cannot be parsed
            System.err.println("Skipping file " + file.getAbsolutePath() + ": " + e.getMessage());
        }
    }

    private static class Liquibase480TransformationVisitor extends ModifierVisitor<Void> {
        @Override
        public Visitable visit(MethodCallExpr n, Void arg) {
            // Fix ExecutorService.getInstance() calls
            if (n.getScope().isPresent()) {
                Expression scope = n.getScope().get();
                if (scope instanceof FieldAccessExpr) {
                    FieldAccessExpr fieldAccess = (FieldAccessExpr) scope;
                    if (fieldAccess.getScope() instanceof Name) {
                        Name scopeName = (Name) fieldAccess.getScope();
                        if ("ExecutorService".equals(scopeName.asString()) && 
                            "getInstance".equals(n.getNameAsString())) {
                            // Replace: ExecutorService.getInstance().getExecutor(database)
                            // With: ExecutorService.getExecutor(database)
                            return new MethodCallExpr(
                                new Name("ExecutorService"),
                                "getExecutor",
                                n.getArguments()
                            );
                        }
                    }
                }
            }

            // Fix StringUtils references
            if (n.getScope().isPresent()) {
                Expression scope = n.getScope().get();
                if (scope instanceof Name) {
                    Name scopeName = (Name) scope;
                    if ("StringUtils".equals(scopeName.asString())) {
                        // Replace: StringUtils.trimToNull(...) with: org.apache.commons.lang3.StringUtils.trimToNull(...)
                        // But we'll replace the import instead for cleaner approach
                    }
                }
            }

            return super.visit(n, arg);
        }

        @Override
        public Visitable visit(ImportDeclaration n, Void arg) {
            // Replace liquibase.util.StringUtils import with org.apache.commons.lang3.StringUtils
            if (n.getNameAsString().equals("liquibase.util.StringUtils")) {
                // Replace the import with the new one
                return new ImportDeclaration(
                    new Name("org.apache.commons.lang3.StringUtils"), 
                    false, 
                    false
                );
            }
            return super.visit(n, arg);
        }
    }
}

